SELECT [Item Ledger Entry].[Posting Date], [Item Ledger Entry].[Location Code], Item.[ADVERTISING MATERIAL], Item.[TRADEMARK CODE], [Item Ledger Entry].[SEASON CODE], [Item Ledger Entry].[LINE CODE], Item.[MODEL ITEM NO_], Item.[DESCRIPTION 2], Item.[Variable Code 01] AS Color, Item.[Variable Code 02] AS [Size], Sum(IIf(Val([quantity])>0,Val([Quantity]),0)) AS PaiaEntrate, Sum(IIf(Val([quantity])<0,Val([Quantity]),0)) AS PaiaUscite, Sum(Val([quantity])) AS Paia, IIf([entry type]=0,"Purchase",IIf([entry type]=1,"Sale",IIf([entry type]=2,"PosAdj",IIf([entry type]=3,"NegAdj",IIf([entry type]=4,"Transfer","UNK"))))) AS TypeMov, [Item Ledger Entry].[Adjustment Type Code], [Item Ledger Entry].[Document No_]
FROM [Item Ledger Entry] INNER JOIN Item ON [Item Ledger Entry].[Item No_] = Item.No_
GROUP BY [Item Ledger Entry].[Posting Date], [Item Ledger Entry].[Location Code], Item.[ADVERTISING MATERIAL], Item.[TRADEMARK CODE], [Item Ledger Entry].[SEASON CODE], [Item Ledger Entry].[LINE CODE], Item.[MODEL ITEM NO_], Item.[DESCRIPTION 2], Item.[Variable Code 01], Item.[Variable Code 02], IIf([entry type]=0,"Purchase",IIf([entry type]=1,"Sale",IIf([entry type]=2,"PosAdj",IIf([entry type]=3,"NegAdj",IIf([entry type]=4,"Transfer","UNK"))))), [Item Ledger Entry].[Adjustment Type Code], [Item Ledger Entry].[Document No_]
HAVING ((([Item Ledger Entry].[Location Code])="PMAG" Or ([Item Ledger Entry].[Location Code])="SPMAG" Or ([Item Ledger Entry].[Location Code])="RMAG" Or ([Item Ledger Entry].[Location Code])="RMAG2") AND ((Item.[ADVERTISING MATERIAL])=0) AND (([Item Ledger Entry].[SEASON CODE])=[forms]![principale]![filtroStagionesourcing]));

